SELECT po.*, s.supplier_name, s.supplier_code, w.warehouse_name, u1.real_name as operator_name, u2.real_name as auditor_name FROM purchase_order po LEFT JOIN supplier s ON po.supplier_id = s.supplier_id LEFT JOIN warehouse w ON po.warehouse_id = w.warehouse_id LEFT JOIN sys_user u1 ON po.operator_id = u1.user_id LEFT JOIN sys_user u2 ON po.auditor_id = u2.user_id
AND po.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND po.supplier_id = #{supplierId}
AND po.status = #{status}
AND po.create_time >= #{startDate}
AND po.create_time <= #{endDate}
ORDER BY po.create_time DESC

SELECT COALESCE(SUM(total_amount), 0) FROM purchase_order
WHERE 1=1

    AND create_time >= #{startDate}


    AND create_time <= #{endDate}
